<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --health-cmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;curl -fsS http://127.0.0.1:8080/health || exit 1&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
